		INVALID_URL_FORMAT: st("assetBrowser.errorInvalidUrlFormat", "The URL format is invalid. Please check and try again."),
		UNSUPPORTED_SOURCE: st("assetBrowser.errorUnsupportedSource", "This URL is not supported. Only Hugging Face and Civitai URLs are allowed."),
		UNAUTHORIZED: st("assetBrowser.errorUnauthorized", "Please sign in to continue."),
