		USER_TOKEN_ACCESS_DENIED: st("assetBrowser.errorUserTokenAccessDenied", "Your API token does not have access to this resource. Please check your token permissions."),
		UNAUTHORIZED_SOURCE: st("assetBrowser.errorUnauthorizedSource", "This resource requires authentication. Please add your API token in settings."),
		ACCESS_FORBIDDEN: st("assetBrowser.errorAccessForbidden", "Access to this resource is forbidden."),
