		RATE_LIMITED: st("assetBrowser.errorRateLimited", "Too many requests. Please try again in a few minutes."),
		SOURCE_SERVER_ERROR: st("assetBrowser.errorSourceServerError", "The source server is experiencing issues. Please try again later."),
		NETWORK_TIMEOUT: st("assetBrowser.errorNetworkTimeout", "Request timed out. Please try again."),
		CONNECTION_REFUSED: st("assetBrowser.errorConnectionRefused", "Unable to connect to the source. Please try again later."),
