/**
* Check if a URL belongs to a specific import source
*/
function validateSourceUrl(url, source) {
	try {
		const hostname = new URL(url).hostname.toLowerCase();
		return source.hostnames.some((h) => hostname === h || hostname.endsWith(`.${h}`));
	} catch {
		return false;
	}
}
