					label: st("queue.jobMenu.inspectAsset", "Inspect asset"),
					icon: "icon-[lucide--zoom-in]",
					disabled: !hasPreviewAsset || !onInspectAsset,
					onClick: onInspectAsset ? () => {
						const item = currentMenuItem();
						if (item) onInspectAsset(item);
					} : void 0
