//#region src/renderer/extensions/minimap/data/AbstractMinimapDataSource.ts
/**
* Abstract base class for minimap data sources
* Provides common functionality and shared implementation
*/
var AbstractMinimapDataSource = class {
	constructor(graph) {
		this.graph = graph;
	}
	getBounds() {
		const nodes = this.getNodes();
		if (nodes.length === 0) return {
			minX: 0,
			minY: 0,
			maxX: 100,
			maxY: 100,
			width: 100,
			height: 100
		};
		const bounds = calculateNodeBounds(nodes.map((node) => ({
			pos: [node.x, node.y],
			size: [node.width, node.height]
		})));
		if (!bounds) return {
			minX: 0,
			minY: 0,
			maxX: 100,
			maxY: 100,
			width: 100,
			height: 100
		};
		return bounds;
	}
	getGroups() {
		if (!this.graph?._groups) return [];
		return this.graph._groups.map((group) => ({
			x: group.pos[0],
			y: group.pos[1],
			width: group.size[0],
			height: group.size[1],
			color: group.color
		}));
	}
	getLinks() {
		if (!this.graph) return [];
		return this.extractLinksFromGraph(this.graph);
	}
	extractLinksFromGraph(graph) {
		const links = [];
		const nodeMap = new Map(this.getNodes().map((n) => [n.id, n]));
		for (const node of graph._nodes) {
			if (!node.outputs) continue;
			const sourceNodeData = nodeMap.get(String(node.id));
			if (!sourceNodeData) continue;
			for (const output of node.outputs) {
				if (!output.links) continue;
				for (const linkId of output.links) {
					const link = graph.links[linkId];
					if (!link) continue;
					const targetNodeData = nodeMap.get(String(link.target_id));
					if (!targetNodeData) continue;
					links.push({
						sourceNode: sourceNodeData,
						targetNode: targetNodeData,
						sourceSlot: link.origin_slot,
						targetSlot: link.target_slot
					});
				}
			}
		}
		return links;
	}
};
