//#region src/renderer/extensions/minimap/data/LiteGraphDataSource.ts
/**
* LiteGraph data source implementation
*/
var LiteGraphDataSource = class extends AbstractMinimapDataSource {
	getNodes() {
		if (!this.graph?._nodes) return [];
		const nodeProgressStates = useExecutionStore().nodeProgressStates;
		return this.graph._nodes.map((node) => {
			const nodeId = String(node.id);
			const executionState = nodeProgressStates[nodeId]?.state ?? null;
			return {
				id: nodeId,
				x: node.pos[0],
				y: node.pos[1],
				width: node.size[0],
				height: node.size[1],
				bgcolor: node.bgcolor,
				mode: node.mode,
				hasErrors: node.has_errors,
				executionState,
				nodeType: node.type
			};
		});
	}
	getNodeCount() {
		return this.graph?._nodes?.length ?? 0;
	}
	hasData() {
		return this.getNodeCount() > 0;
	}
};
