	if (latentish) return isLightTheme ? "rgba(59,130,246,0.68)" : "rgba(96,165,250,0.75)";
	if (sampleish) return isLightTheme ? "rgba(168,85,247,0.68)" : "rgba(192,132,252,0.75)";
	if (postish) return isLightTheme ? "rgba(34,197,94,0.68)" : "rgba(52,211,153,0.75)";
	return isLightTheme ? "rgba(130,130,130,0.45)" : "rgba(170,170,170,0.4)";
