//#region src/renderer/core/thumbnail/graphThumbnailRenderer.ts
/**
* Create a thumbnail of the current canvas's active graph.
* Used by workflow thumbnail generation.
*/
function createGraphThumbnail() {
	const canvasStore = useCanvasStore();
	const graph = useWorkflowStore().activeSubgraph || canvasStore.canvas?.graph;
	if (!graph || !graph._nodes || graph._nodes.length === 0) return null;
	const width = 250;
	const height = 200;
	const bounds = calculateNodeBounds(graph._nodes);
	if (!bounds) return null;
	const scale = calculateMinimapScale(bounds, width, height);
	const canvas = document.createElement("canvas");
	canvas.width = width;
	canvas.height = height;
	renderMinimapToCanvas(canvas, graph, {
		bounds,
		scale,
		settings: {
			nodeColors: true,
			showLinks: false,
			showGroups: true,
			renderBypass: false,
			renderError: false,
			semanticLayers: false
		},
		width,
		height
	});
	const dataUrl = canvas.toDataURL();
	const ctx = canvas.getContext("2d");
	if (ctx) ctx.clearRect(0, 0, width, height);
	return dataUrl;
}
