	const openWorkflow = async (workflow) => {
		if (isActive(workflow)) return workflow;
		if (!openWorkflowPaths.value.includes(workflow.path)) openWorkflowPaths.value.push(workflow.path);
		const loadedWorkflow = await workflow.load();
		activeWorkflow.value = loadedWorkflow;
		app.canvas.bg_tint = loadedWorkflow.tintCanvasBg;
		const historyIndex = tabActivationHistory.value.indexOf(workflow.path);
		if (historyIndex !== -1) tabActivationHistory.value.splice(historyIndex, 1);
		tabActivationHistory.value.push(workflow.path);
		if (tabActivationHistory.value.length > MAX_HISTORY_SIZE) tabActivationHistory.value.shift();
		return loadedWorkflow;
	};
	const getUnconflictedPath = (basePath) => {
		const { directory, filename, suffix } = getPathDetails(basePath);
		let counter = 2;
		let newPath = basePath;
		while (workflowLookup.value[newPath]) {
			newPath = `${directory}/${filename} (${counter}).${suffix}`;
			counter++;
		}
		return newPath;
	};
