		try {
			data = data.slice(data.indexOf("{"));
			workflow = JSON.parse(data);
		} catch (err) {
			try {
				data = data.slice(data.indexOf("workflow\n"));
				data = data.slice(data.indexOf("{"));
				workflow = JSON.parse(data);
			} catch (error) {
				workflow = null;
			}
		}
		if (workflow && workflow.version && workflow.nodes && workflow.extra) await app.loadGraphData(workflow);
